+            "id": "test-conv",
+            "title": "App Support",
+            "mapping": {
+                "node1": {
+                    "message": {
+                        "author": {"role": "user"},
+                        "content": {"parts": ["Hello!"]},
+                        "create_time": 1700000000.0
+                    }
+                }
+            }
+        });
